import{_ as a,o,c as i,ah as t}from"./chunks/framework.Bi9enVNS.js";const u=JSON.parse('{"title":"数据与视图概念","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md","lastUpdated":1774205896000}'),l={name:"guide/concepts.md"};function n(c,e,r,d,s,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="数据与视图概念" tabindex="-1">数据与视图概念 <a class="header-anchor" href="#数据与视图概念" aria-label="Permalink to &quot;数据与视图概念&quot;">​</a></h1><p>理解这几个概念后，VLT 的协议和 UI 会容易很多。</p><h2 id="project" tabindex="-1">project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;project&quot;">​</a></h2><p><code>project</code> 是批次级字段，用来表示日志属于哪个逻辑项目。它也是 token 写入权限和幂等键的一部分。</p><h2 id="environment" tabindex="-1">environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;environment&quot;">​</a></h2><p><code>environment</code> 同样是批次级字段，用来区分 <code>dev</code>、<code>staging</code>、<code>prod</code> 之类的环境。</p><h2 id="source" tabindex="-1">source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;source&quot;">​</a></h2><p>VLT 用 <code>SourceRef</code> 表示日志来源。一个来源至少要能解析出：</p><ul><li><code>source_name</code></li><li><code>source_type</code></li></ul><p>还可以带：</p><ul><li><code>source_id</code></li><li><code>namespace</code></li><li><code>instance_id</code></li><li><code>labels</code></li></ul><h2 id="trace-与-span" tabindex="-1">trace 与 span <a class="header-anchor" href="#trace-与-span" aria-label="Permalink to &quot;trace 与 span&quot;">​</a></h2><ul><li><code>trace_id</code> 表示整条调用链</li><li><code>span_id</code> 表示链路中的一个局部片段</li><li><code>trace_flags</code> 保留 Trace 元数据</li></ul><p>当前实现会校验它们的格式，但 topology 并不是按 span parent-child 推导的。</p><h2 id="source-fingerprint" tabindex="-1">source_fingerprint <a class="header-anchor" href="#source-fingerprint" aria-label="Permalink to &quot;source_fingerprint&quot;">​</a></h2><p>这是当前实现里非常关键的概念。它由以下输入计算而来：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project + environment + source_type + source_name + instance_id</span></span></code></pre></div><p>用途：</p><ul><li>Timeline 中作为 lane 标识</li><li>Topology 中作为 node 标识</li><li>记录同一来源实例级别的聚合</li></ul><h2 id="timeline-lane" tabindex="-1">timeline lane <a class="header-anchor" href="#timeline-lane" aria-label="Permalink to &quot;timeline lane&quot;">​</a></h2><p>Timeline 中的每个 lane 对应一个 <code>source_fingerprint</code>。也就是说，lane 代表的是“来源实例级别视图”，而不是抽象服务名视图。</p><h2 id="topology-edge" tabindex="-1">topology edge <a class="header-anchor" href="#topology-edge" aria-label="Permalink to &quot;topology edge&quot;">​</a></h2><p>Topology 的边来自“同一条 Trace 内，相邻且来源不同的片段”。这意味着：</p><ul><li>它反映的是日志时序上的流转</li><li>它不是 span DAG</li><li>连续相同来源会先折叠，减少错误自环</li></ul><h2 id="来源树" tabindex="-1">来源树 <a class="header-anchor" href="#来源树" aria-label="Permalink to &quot;来源树&quot;">​</a></h2><p><code>GET /v1/sources</code> 返回的是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source_type -&gt; source_name -&gt; instance_id</span></span></code></pre></div><p>这更适合回答“现在有哪些来源实例在发日志”，而不是“某一条 Trace 是怎么走的”。</p><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>proto/vlt/common/v1/common.proto</code></li><li><code>proto/vlt/logs/v1/logs.proto</code></li><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',30)])])}const m=a(l,[["render",n]]);export{u as __pageData,m as default};
